import{_ as s,o as t,c as i,a3 as e}from"./chunks/framework.CGpxwYOt.js";const h=JSON.parse('{"title":"2.2 世界BOSS","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 世界BOSS 指的是出现在公共地图上的，服务器内所有玩家都可以看到并进行攻击的BOSS。 术语如下： TS：原版杀戮风暴 部分BOSS 由于机制、PVP、数值的影响，想要加入这些BOSS ","frontmatter":{"title":"2.2 世界BOSS","description":"本节点为目录/结构标题，具体操作内容见其下级章节。 世界BOSS 指的是出现在公共地图上的，服务器内所有玩家都可以看到并进行攻击的BOSS。 术语如下： TS：原版杀戮风暴 部分BOSS 由于机制、PVP、数值的影响，想要加入这些BOSS ","outline":"deep"},"headers":[],"relativePath":"pve/2-2.md","filePath":"pve/2-2.md","lastUpdated":1782387794000}'),u={name:"pve/2-2.md"};function g(p,a,l,r,o,d){return t(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="_2-2-世界boss" tabindex="-1">2.2 世界BOSS <a id="s150-1b14223c"></a> <a class="header-anchor" href="#_2-2-世界boss" aria-label="Permalink to &quot;2.2 世界BOSS &lt;a id=&quot;s150-1b14223c&quot;&gt;&lt;/a&gt;&quot;">​</a></h1><p>本节点为目录/结构标题，具体操作内容见其下级章节。</p><h2 id="_2-2-1世界boss的定义和相关术语" tabindex="-1">2.2.1世界BOSS的定义和相关术语 <a id="s151-629a958c"></a> <a class="header-anchor" href="#_2-2-1世界boss的定义和相关术语" aria-label="Permalink to &quot;2.2.1世界BOSS的定义和相关术语 &lt;a id=&quot;s151-629a958c&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>世界BOSS 指的是出现在公共地图上的，服务器内所有玩家都可以看到并进行攻击的BOSS。</p><p>术语如下：</p><p>TS：原版杀戮风暴</p><h2 id="_2-2-2-参加攻打世界boss活动的前置要求" tabindex="-1">2.2.2 参加攻打世界BOSS活动的前置要求 <a id="s152-4164d666"></a> <a class="header-anchor" href="#_2-2-2-参加攻打世界boss活动的前置要求" aria-label="Permalink to &quot;2.2.2 参加攻打世界BOSS活动的前置要求 &lt;a id=&quot;s152-4164d666&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>部分BOSS 由于机制、PVP、数值的影响，想要加入这些BOSS 的击杀团队需要满足一定的条件。具体条件参考各个BOSS 目录或者咨询群内最新要求。并且BOSS击杀团队不允许参与玩家挂机。</p><h2 id="_2-2-3-参加攻打世界boss活动的收益" tabindex="-1">2.2.3 参加攻打世界BOSS活动的收益 <a id="s153-d492d943"></a> <a class="header-anchor" href="#_2-2-3-参加攻打世界boss活动的收益" aria-label="Permalink to &quot;2.2.3 参加攻打世界BOSS活动的收益 &lt;a id=&quot;s153-d492d943&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>击杀BOSS 后会掉落头领强化剂，可以ROLL 点获取。</p><p>击杀BOSS 后可以获得任务奖励。</p><p>击杀强大的世界BOSS 后会掉落专属道具，会拍卖。拍卖结束后会通过邮件的方式给每个参与成员发放奖励。</p><h2 id="_2-2-4-利维坦与卡里迪斯" tabindex="-1">2.2.4 利维坦与卡里迪斯 <a id="s154-e9ad4b49"></a> <a class="header-anchor" href="#_2-2-4-利维坦与卡里迪斯" aria-label="Permalink to &quot;2.2.4 利维坦与卡里迪斯 &lt;a id=&quot;s154-e9ad4b49&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>利维坦参考贴吧攻略：<a href="https://tieba.baidu.com/p/7121220239?see_lz=1" target="_blank" rel="noreferrer">https://tieba.baidu.com/p/7121220239?see_lz=1</a></p><h2 id="_2-2-5-克拉肯-kraken" tabindex="-1">2.2.5 克拉肯（kraken） <a id="s155-c359c3b0"></a> <a class="header-anchor" href="#_2-2-5-克拉肯-kraken" aria-label="Permalink to &quot;2.2.5 克拉肯（kraken） &lt;a id=&quot;s155-c359c3b0&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>参考视频：待更新</p><p>任务团无装备评分要求，要求提前到克拉肯下岛准备，如果准备参加周日晚上</p><p>10：30 的克拉肯，那么你就要放弃噩梦。</p><p>克拉肯刷新时或者进入战斗状态时在附近可以接到以下任务：</p><figure class="image-flow" data-pdf-anchor="克拉肯刷新时或者进入战斗状态时在附近可以接到以下任务："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1882.jpeg" alt="图示" loading="lazy"></figure><p>打死BOSS 会爆触须和墨囊，可以去鱼类贩卖台卖钱，数量有限，需要手速快，</p><p>有可能被红名打，小号自求多福。</p><p>注意！！！如果一开始没接到任务，意味着会出T2 克拉肯，T1 克拉肯会在剩60%血时变身为T2 克拉肯，这时候才能接到T2 克拉肯的任务。</p><h2 id="_2-2-6魔法机甲兵器-大甲虫-与安琪仕" tabindex="-1">2.2.6魔法机甲兵器（大甲虫）与安琪仕 <a id="s156-3e0b7936"></a> <a class="header-anchor" href="#_2-2-6魔法机甲兵器-大甲虫-与安琪仕" aria-label="Permalink to &quot;2.2.6魔法机甲兵器（大甲虫）与安琪仕 &lt;a id=&quot;s156-3e0b7936&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>参考视频：待更新</p><p>魔法机甲兵器（大甲虫）在魔法之地接每日任务处NPC 接取，无论甲虫是否已经开始打。</p><p>红框处NPC 接取任务，</p><p>蓝框处传送到打BOSS 的地</p><p>方。</p><p>传送到目的地后，有炮车就叫炮车，没炮车就背炮枪。拿枪台子如下：</p><figure class="image-flow" data-pdf-anchor="传送到目的地后，有炮车就叫炮车，没炮车就背炮枪。拿枪台子如下："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1890.jpeg" alt="图示" loading="lazy"></figure><p>在打甲虫的时候，不要攻击梅德达魔法学校的守护者。</p><p>甲虫任务和箱子保底奖励如下：</p><p>甲虫箱子还会概率开出零件，能卖几千金，如下：</p><figure class="image-flow" data-pdf-anchor="甲虫箱子还会概率开出零件，能卖几千金，如下："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1898.jpeg" alt="图示" loading="lazy"></figure><p>当然你也可以用10 个自己合成一个7 天的甲虫来玩，很强。玩家坐在甲虫里面是无敌的。</p><p>甲虫兵器如下：</p><figure class="image-flow" data-pdf-anchor="甲虫兵器如下："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1896.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="甲虫兵器如下："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1897.jpeg" alt="图示" loading="lazy"></figure><h2 id="_2-2-7-摩尔普斯与兰格莉" tabindex="-1">2.2.7 摩尔普斯与兰格莉 <a id="s157-c6f066c9"></a> <a class="header-anchor" href="#_2-2-7-摩尔普斯与兰格莉" aria-label="Permalink to &quot;2.2.7 摩尔普斯与兰格莉 &lt;a id=&quot;s157-c6f066c9&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>内战结束后更新</p><figure class="image-flow" data-pdf-anchor="内战结束后更新"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1911.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="内战结束后更新"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1912.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="内战结束后更新"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1913.jpeg" alt="图示" loading="lazy"></figure><h2 id="_2-2-8-黑龙-bd" tabindex="-1">2.2.8 黑龙（BD） <a id="s158-57cd783d"></a> <a class="header-anchor" href="#_2-2-8-黑龙-bd" aria-label="Permalink to &quot;2.2.8 黑龙（BD） &lt;a id=&quot;s158-57cd783d&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>黑龙参考视频：BV1aM4m127FU</p><p>进黑龙团需要你首先达到以下4 个条件：</p><p>1）装备评分达到一万六千分及以上</p><p>2）在满BUFF 下血量达到四万及以上</p><p>3）进入语音频道听从指挥</p><p>4）知晓黑龙BOSS 机制</p><p>黑龙主要有以下机制：</p><p>大地强击、黑色气息侵袭、黑龙鳞片、裂岩斩。黑龙这些技能都是有读条的，非极限情况都是可以避开的。</p><p>大地强击是非常好避开的一个技能，只需要保证角色的脚不接触地面即可避免伤害。</p><p>黑色气息侵袭为随机沉默一些玩家，头顶会出现箭头指示，同时角色被黑色气息包裹，需要接触一个类似哈迪尔农场最终BOSS 的灵魂来解除侵袭，你可以使用坐骑来加快移动速度，解除侵袭对击杀黑龙团队来说是非常重要的。</p><p>黑龙鳞片时，玩家会被沉默无法使用技能，需要找到黑龙掉下来的鳞片按F 获得无敌状态，若没有采集到鳞片也可以靠近采集到鳞片的玩家，采集到鳞片的玩家，头顶会有一个指向玩家的箭头。当然你也可以使用铁壁的无敌技能来躲避伤害。</p><p>裂岩斩虽然读条很快，但不是读完条就放出来的，在读条的同时，地面上会出现一个个蓝色圈圈，2~3 秒后就会由黑龙从近到远释放技能，避开这些蓝色圈圈就不会被裂岩斩打到。</p><p>黑龙的刷新时间为：周日晚上9 点。</p><h2 id="_2-2-9-雷神巨翼青鸾-大鸟、twt" tabindex="-1">2.2.9 雷神巨翼青鸾（大鸟、TWT） <a id="s159-cebabed6"></a> <a class="header-anchor" href="#_2-2-9-雷神巨翼青鸾-大鸟、twt" aria-label="Permalink to &quot;2.2.9 雷神巨翼青鸾（大鸟、TWT） &lt;a id=&quot;s159-cebabed6&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>内战结束后更新</p><h2 id="_2-2-10-庭院安塔伦" tabindex="-1">2.2.10 庭院安塔伦 <a id="s160-772e5498"></a> <a class="header-anchor" href="#_2-2-10-庭院安塔伦" aria-label="Permalink to &quot;2.2.10 庭院安塔伦 &lt;a id=&quot;s160-772e5498&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>内战结束后更新</p><h2 id="_2-2-11-叛乱系列boss-待更新" tabindex="-1">2.2.11 叛乱系列BOSS（待更新） <a id="s161-a6676350"></a> <a class="header-anchor" href="#_2-2-11-叛乱系列boss-待更新" aria-label="Permalink to &quot;2.2.11 叛乱系列BOSS（待更新） &lt;a id=&quot;s161-a6676350&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>叛乱系列BOSS 除了每次服务器维护后较少有人开团。</p><p>公主梦戒指任务需要击杀该系列BOSS，具体情况请参考戒指攻略。</p><p>叛乱BOSS 刷新位置如下图所示：待更新</p><h2 id="_2-2-12-美杜莎、格蓝与蕾娜-jmg" tabindex="-1">2.2.12 美杜莎、格蓝与蕾娜（JMG） <a id="s162-efb00d8f"></a> <a class="header-anchor" href="#_2-2-12-美杜莎、格蓝与蕾娜-jmg" aria-label="Permalink to &quot;2.2.12 美杜莎、格蓝与蕾娜（JMG） &lt;a id=&quot;s162-efb00d8f&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>JMG 指的是美杜莎、格蓝和蕾娜3 个BOSS。一般开团只击杀1 阶段BOSS 二不击杀2 阶段BOSS。JMG 会在煦日之野和墟境之口刷新，刷新时间为游戏时间6 点。</p><p>位置如图所示：</p><figure class="image-flow" data-pdf-anchor="位置如图所示："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1932.jpeg" alt="图示" loading="lazy"></figure><p>蛇女：</p><p>格蓝、蕾娜：</p><h2 id="_2-2-13-神之庭院战争boss" tabindex="-1">2.2.13 神之庭院战争BOSS <a id="s163-53a20a70"></a> <a class="header-anchor" href="#_2-2-13-神之庭院战争boss" aria-label="Permalink to &quot;2.2.13 神之庭院战争BOSS &lt;a id=&quot;s163-53a20a70&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>神之庭院每次进入战争状态都会刷新4 只BOSS，其中3 只位置固定，安塔伦影子在2 个地方随机刷新（维护后不刷新）。</p><p>击杀完4 个BOSS 后的等级分数如图所示：</p><figure class="image-flow" data-pdf-anchor="击杀完4 个BOSS 后的等级分数如图所示："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1939.jpeg" alt="图示" loading="lazy"></figure><p>一般英雄都会开团带领大家去击杀BOSS。</p><p>每只庭院BOSS 都必定掉落新月紫石晶，概率掉落金箱子。</p><p>经常来参与庭院BOSS 且无快速移动手段的玩家可以在图示位置购买传送石。</p><figure class="image-flow" data-pdf-anchor="经常来参与庭院BOSS 且无快速移动手段的玩家可以在图示位置购买传送石。"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1938.jpeg" alt="图示" loading="lazy"></figure><p>传送石不仅可以提高你的移动效率，还可以避免你被路上的怪物打死。</p><figure class="image-flow" data-pdf-anchor="传送石不仅可以提高你的移动效率，还可以避免你被路上的怪物打死"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1945.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="传送石不仅可以提高你的移动效率，还可以避免你被路上的怪物打死"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1946.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="传送石不仅可以提高你的移动效率，还可以避免你被路上的怪物打死"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1947.jpeg" alt="图示" loading="lazy"></figure><h2 id="_2-2-14-纳扎尔" tabindex="-1">2.2.14 纳扎尔 <a id="s164-d086c45a"></a> <a class="header-anchor" href="#_2-2-14-纳扎尔" aria-label="Permalink to &quot;2.2.14 纳扎尔 &lt;a id=&quot;s164-d086c45a&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>纳扎尔刷新位置在自由岛下方海底，如图所示：</p><figure class="image-flow" data-pdf-anchor="纳扎尔刷新位置在自由岛下方海底，如图所示："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1952.jpeg" alt="图示" loading="lazy"></figure><p>纳扎尔属于公主梦戒指任务所需BOSS，一般较少开团。（周日晚上打完克拉肯可以注意有没有开团）。下图为BOSS 击杀任务和全团roll 点掉落。</p><figure class="image-flow" data-pdf-anchor="可以注意有没有开团）。下图为BOSS 击杀任务和全团roll 点掉落。"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1953.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="可以注意有没有开团）。下图为BOSS 击杀任务和全团roll 点掉落。"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1954.jpeg" alt="图示" loading="lazy"></figure><h2 id="_2-2-15-德翡纳幽灵船" tabindex="-1">2.2.15 德翡纳幽灵船 <a id="s165-a50beb47"></a> <a class="header-anchor" href="#_2-2-15-德翡纳幽灵船" aria-label="Permalink to &quot;2.2.15 德翡纳幽灵船 &lt;a id=&quot;s165-a50beb47&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>中国时间周一二四六早上9 点刷新在黄金之海，10 点消失。</p><p>轮流刷新在靠近西大和靠近东大的海域。</p><p>打完掉落15 个德翡纳幽灵船的石板，可以去双冠或者黎明的黑暗商人处贩卖黑炭，满货率144 一包。但是如果没打掉幽灵船消失掉落的箱子只有海盗能开，而且只有海盗能分解出黑炭，海盗也可以跑去自由岛卖，其他势力即使抢到了海盗的德翡纳幽灵船的庇护石板也没有任何作用。海盗拆解随机给黑炭，卖的话吃货率。</p><h2 id="_2-2-16-海盗守卫boss" tabindex="-1">2.2.16 海盗守卫BOSS <a id="s166-d1f8ea2d"></a> <a class="header-anchor" href="#_2-2-16-海盗守卫boss" aria-label="Permalink to &quot;2.2.16 海盗守卫BOSS &lt;a id=&quot;s166-d1f8ea2d&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>海盗守卫BOSS 只有摩尔普斯和兰格莉是有任务的，守卫德翡纳幽灵船只有传送门和奖励（9.5 开始有任务了）。摩尔普斯和兰格莉消失后的箱子都是只能摸一次，任意一个玩家摸了之后，其他玩家就不能摸了。</p><p>接取守卫BOSS 任务的NPC 会在BOSS 刷新后，在海盗大厅刷新，分别位于酒</p><p>店老板左右两侧，如下图：</p><figure class="image-flow" data-pdf-anchor="店老板左右两侧，如下图："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1960.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="店老板左右两侧，如下图："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1961.jpeg" alt="图示" loading="lazy"></figure><p>接取任务后需要在2 小时内与BOSS 对话，对话完后等BOSS 自然消失再回到海盗大厅找接取任务的NPC 交任务就行，任务奖励和东西大陆击杀BOSS 的是一样的。</p><p>海盗不同在于，boss 自然消失后会留下一个只有海盗可以开的宝箱（限定一个人，</p><p>只有第一个交互的可以开），宝箱会出的东西和杀BOSS 是一样的，不过大多数情况下只会给一个金箱子（爆率比起击杀BOSS，要相当感人）。</p><figure class="image-flow" data-pdf-anchor="经开始打。"><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1889.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor=""><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1903.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor=""><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1904.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor=""><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1905.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor=""><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1906.jpeg" alt="图示" loading="lazy"></figure><figure class="image-flow" data-pdf-anchor="格蓝、蕾娜："><img src="https://psyduuuuuck.github.io/sgsj/assets/img_xref_1933.jpeg" alt="图示" loading="lazy"></figure>',109)])])}const f=s(u,[["render",g]]);export{h as __pageData,f as default};
